type CalculationSnapshot = {
  inputs: string[];
  result: string;
  notes?: string;
};

type ChartPoint = {
  label: string;
  value: number;
};

type TooltipPayload = {
  name?: string;
  value?: number | string;
  color?: string;
  payload?: Record<string, unknown>;
};

type TooltipProps = {
  active?: boolean;
  label?: string | number;
  payload?: TooltipPayload[];
};

type ChartContext = {
  title: string;
  path: string;
  inputs: ChartPoint[];
  results: ChartPoint[];
  primaryValue: number;
  primaryLabel: string;
};

