function parseNumericValue(value: string) {
  const normalized = value.replace(/,/g, "").replace(/\u2212/g, "-");
  const parentheses = normalized.match(/\((\d+(\.\d+)?)\)/);
  if (parentheses) return -Number(parentheses[1]);
  const match = normalized.match(/-?\d+(\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function cleanLabel(label: string) {
  const cleaned = label
    .replace(/\([^)]*\)/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\bmonthly\b/gi, "Mo.")
    .replace(/\bannual\b/gi, "Ann.")
    .replace(/\bpercentage\b/gi, "%");
  return cleaned.length > 24 ? `${cleaned.slice(0, 22).trim()}...` : cleaned;
}

function dedupe(points: ChartPoint[]) {
  const seen = new Set<string>();
  return points.filter((point) => {
    if (!Number.isFinite(point.value)) return false;
    const key = `${point.label.toLowerCase()}:${point.value}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function getPageTitle() {
  if (typeof document === "undefined") return "Calculator";
  return document.querySelector("h1")?.textContent?.replace(/\s+/g, " ").trim() || "Calculator";
}

function getPath() {
  if (typeof window === "undefined") return "";
  return window.location.pathname.toLowerCase();
}

function snapshotNumbers(snapshot: CalculationSnapshot | null): Pick<ChartContext, "inputs" | "results"> {
  if (!snapshot) return { inputs: [], results: [] };

  const inputs = dedupe(
    snapshot.inputs
      .map((input) => {
        const [rawLabel, ...rest] = input.split(":");
        const value = parseNumericValue(rest.join(":"));
        return value === null ? null : { label: cleanLabel(rawLabel || "Input"), value };
      })
      .filter((point): point is ChartPoint => Boolean(point)),
  );

  const results = dedupe(
    snapshot.result
      .split("|")
      .map((result, index) => {
        const [maybeLabel, ...rest] = result.split(":");
        const value = parseNumericValue(result);
        const label = rest.length ? maybeLabel : `Result ${index + 1}`;
        return value === null ? null : { label: cleanLabel(label), value };
      })
      .filter((point): point is ChartPoint => Boolean(point)),
  );

  return { inputs, results };
}

function createContext(snapshot: CalculationSnapshot | null): ChartContext {
  const { inputs, results } = snapshotNumbers(snapshot);
  const primary = results[0] || inputs[0] || { label: "Result", value: 0 };
  return {
    title: getPageTitle(),
    path: getPath(),
    inputs,
    results,
    primaryValue: primary.value,
    primaryLabel: primary.label,
  };
}

function findValue(points: ChartPoint[], matcher: RegExp, fallback = 0) {
  return points.find((point) => matcher.test(point.label))?.value ?? fallback;
}

function isAny(context: ChartContext, matcher: RegExp) {
  return matcher.test(`${context.path} ${context.title}`.toLowerCase());
}

