  if (isAny(context, /pregnancy|due-date|conception|ovulation|period/)) return "pregnancy-timeline";
  if (isAny(context, /bmi|body-fat|ideal-weight|healthy-weight|overweight|gfr|bac|body-type|body-surface|lean-body/)) return "health-scale";
  if (isAny(context, /pace|one-rep|max|heart|calories-burned|protein|carbohydrate|fat-intake/)) return "fitness-bars";
  if (isAny(context, /mortgage|loan|amortization|payoff|refinance|repayment|payment|debt|credit-card|lease/)) return "loan-dual";
  if (isAny(context, /roi|irr|investment|average-return|payback|present-value|future-value/)) return "investment-bars";
  if (isAny(context, /income-tax|take-home|salary|paycheck|pension|social-security|commission/)) return "income-stack";
  if (isAny(context, /compound|savings|retirement|401k|cd-|bond|annuity|interest|finance|apr|apy/)) return "financial-growth";
  if (isAny(context, /percent|percentage|discount|margin|markup|error/)) return "percent-bars";
  if (isAny(context, /standard-deviation|statistics|mean|median|mode|z-score|probability|confidence|sample-size/)) return "bell";
  if (isAny(context, /area|volume|surface-area|circle|triangle|square-footage|stair|roof|tile|mulch|gravel/)) return "geometry";
  if (isAny(context, /ph-|titration|ideal-gas|boyles|charles|molarity|molecular|stoichiometry|atom|chemical|dilution|buffer|yield/)) return "chem-line";
  if (isAny(context, /newton|kinetic|potential|force|acceleration|momentum|work|power|pressure|torque|wavelength|frequency|capacitance|electric-field/)) return "science-line";
  if (isAny(context, /currency|unit|temperature|weight|speed|height|mass|density|roman|conversion/)) return "conversion-bars";
  if (isAny(context, /age|date|day|time|duration|timezone|time-zone/)) return "date-timeline";
  if (isAny(context, /fuel|gas|mileage|road-trip|tire|transport/)) return "transport-line";
  if (isAny(context, /youtube|subscriber|shorts|cpm|channel/)) return "youtube-line";
