function formatNumber(value: unknown) {
  const number = Number(value);
  if (!Number.isFinite(number)) return String(value ?? "");
  return number.toLocaleString(undefined, { maximumFractionDigits: Math.abs(number) < 10 ? 2 : 0 });
}

function compact(value: number) {
  const absolute = Math.abs(value);
  if (absolute >= 1_000_000_000) return `${(value / 1_000_000_000).toFixed(1)}B`;
  if (absolute >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
  if (absolute >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
  return formatNumber(value);
}

function tooltipFormatter(value: unknown) {
  return formatNumber(value);
}

function ChartTooltip({ active, payload, label }: TooltipProps) {
  if (!active || !payload?.length) return null;
  return (
    <div className="rounded-xl border border-border bg-card/95 px-3 py-2 text-xs shadow-xl backdrop-blur">
      {label !== undefined && <p className="mb-1 font-black text-foreground">{label}</p>}
      <div className="space-y-1">
        {payload.map((item, index) => (
          <p key={`${item.name || "value"}-${index}`} className="flex items-center justify-between gap-4 text-muted-foreground">
            <span className="inline-flex items-center gap-2">
              <span className="h-2 w-2 rounded-full" style={{ backgroundColor: item.color || COLORS.purple }} />
              {item.name || "Value"}
            </span>
            <span className="font-black text-foreground">{formatNumber(item.value)}</span>
          </p>
        ))}
      </div>
    </div>
  );
}

function moneySeed(context: ChartContext) {
  const amount =
    findValue(context.inputs, /amount|balance|price|principal|loan|mortgage|investment|savings|income|salary|cost|value/i) ||
    Math.abs(context.primaryValue) ||
    1000;
  return Math.max(1, Math.abs(amount));
}

function rateSeed(context: ChartContext, fallback = 6) {
  const rate = findValue(context.inputs, /rate|apr|apy|return|interest|yield|growth|cpm|rpm/i, fallback);
  return Number.isFinite(rate) ? Math.max(0, Math.min(40, rate)) : fallback;
}

function yearsSeed(context: ChartContext, fallback = 10) {
  const years = findValue(context.inputs, /year|term|period|duration|age/i, fallback);
  if (!Number.isFinite(years)) return fallback;
  return Math.max(1, Math.min(40, years));
}

function financialGrowthData(context: ChartContext) {
  const principalStart = moneySeed(context);
  const monthly = Math.max(0, findValue(context.inputs, /monthly|contribution|deposit|payment/i, 0));
  const rate = rateSeed(context, 6) / 100;
  const years = Math.round(yearsSeed(context, 12));
  const step = Math.max(1, Math.ceil(years / 10));
  const data: Array<{ year: string; principal: number; returns: number; total: number }> = [];
  let balance = principalStart;
  let principal = principalStart;
  for (let year = 0; year <= years; year += 1) {
    if (year > 0) {
      for (let month = 0; month < 12; month += 1) {
        principal += monthly;
        balance = (balance + monthly) * (1 + rate / 12);
      }
    }
    if (year === 0 || year === years || year % step === 0) {
      data.push({ year: `Year ${year}`, principal: Math.round(principal), returns: Math.round(Math.max(0, balance - principal)), total: Math.round(balance) });
    }
  }
  return data;
}

function loanScheduleData(context: ChartContext) {
  const amount = moneySeed(context);
  const rate = rateSeed(context, 6) / 100 / 12;
  const years = yearsSeed(context, 30);
  const months = Math.max(12, Math.min(480, Math.round(years * 12)));
  const payment = rate
    ? amount * (rate * Math.pow(1 + rate, months)) / (Math.pow(1 + rate, months) - 1)
    : amount / months;
  const balanceData: Array<{ label: string; balance: number; principalPaid: number }> = [];
  const splitData: Array<{ year: string; principal: number; interest: number }> = [];
  let balance = amount;
  let yearPrincipal = 0;
  let yearInterest = 0;
  const balanceStep = Math.max(1, Math.ceil(months / 10));

  balanceData.push({ label: "Start", balance: Math.round(balance), principalPaid: 0 });
  for (let month = 1; month <= months; month += 1) {
    const interest = balance * rate;
    const principal = Math.max(0, Math.min(balance, payment - interest));
    balance = Math.max(0, balance - principal);
    yearPrincipal += principal;
    yearInterest += interest;
    if (month % 12 === 0 || month === months) {
      splitData.push({ year: `Year ${Math.ceil(month / 12)}`, principal: Math.round(yearPrincipal), interest: Math.round(yearInterest) });
      yearPrincipal = 0;
      yearInterest = 0;
    }
    if (month % balanceStep === 0 || month === months) {
      balanceData.push({ label: months <= 24 ? `Mo. ${month}` : `Yr ${Math.round(month / 12)}`, balance: Math.round(balance), principalPaid: Math.round(amount - balance) });
    }
  }

  return { balanceData, splitData: splitData.filter((_, index) => index % Math.max(1, Math.ceil(splitData.length / 8)) === 0).slice(0, 8) };
}

function donutData(context: ChartContext, kind: string) {
  if (kind === "macro-donut") {
    const protein = findValue(context.results, /protein/i, findValue(context.inputs, /protein/i, 120));
    const carbs = findValue(context.results, /carb/i, findValue(context.inputs, /carb/i, 220));
    const fat = findValue(context.results, /fat/i, findValue(context.inputs, /fat/i, 70));
    return [
      { name: "Protein", value: Math.max(0, protein) },
      { name: "Carbs", value: Math.max(0, carbs) },
      { name: "Fat", value: Math.max(0, fat) },
    ];
  }
  if (kind === "energy-donut") {
    const total = Math.max(1, Math.abs(context.primaryValue) || moneySeed(context));
    return [
      { name: "BMR", value: Math.round(total * 0.62) },
      { name: "Activity", value: Math.round(total * 0.20) },
      { name: "NEAT", value: Math.round(total * 0.08) },
      { name: "Thermic Food", value: Math.round(total * 0.10) },
    ];
  }
  const source = context.inputs.filter((point) => !/income|rate|total|remaining|balance/i.test(point.label) && point.value > 0);
  const fallback = context.results.filter((point) => point.value > 0);
  return (source.length >= 2 ? source : fallback).slice(0, 8).map((point) => ({ name: point.label, value: Math.abs(point.value) }));
}

function healthScale(context: ChartContext) {
  const text = `${context.path} ${context.title}`.toLowerCase();
  if (/bmi|overweight/.test(text)) {
    return {
      domain: [10, 45],
      value: Math.max(10, Math.min(45, Math.abs(context.primaryValue) || 25)),
      segments: [
        { name: "Low", value: 8.5, color: COLORS.red },
        { name: "Borderline", value: 6.5, color: COLORS.amber },
        { name: "Healthy", value: 6.4, color: COLORS.green },
        { name: "Over", value: 5.1, color: COLORS.amber },
        { name: "High", value: 9, color: COLORS.red },
      ],
    };
  }
  if (/gfr/.test(text)) {
    return {
      domain: [0, 120],
      value: Math.max(0, Math.min(120, Math.abs(context.primaryValue) || 90)),
      segments: [
        { name: "Severe", value: 30, color: COLORS.red },
        { name: "Reduced", value: 30, color: COLORS.amber },
        { name: "Mild", value: 30, color: COLORS.blue },
        { name: "Normal", value: 30, color: COLORS.green },
      ],
    };
  }
  if (/bac/.test(text)) {
    return {
      domain: [0, 0.30],
      value: Math.max(0, Math.min(0.30, Math.abs(context.primaryValue) || 0.03)),
      segments: [
        { name: "Low", value: 0.03, color: COLORS.green },
        { name: "Caution", value: 0.05, color: COLORS.amber },
        { name: "Danger", value: 0.12, color: COLORS.orange },
        { name: "Severe", value: 0.10, color: COLORS.red },
      ],
    };
  }
  return {
    domain: [0, 100],
    value: Math.max(0, Math.min(100, Math.abs(context.primaryValue) || 50)),
    segments: [
      { name: "Low", value: 25, color: COLORS.amber },
      { name: "Target", value: 35, color: COLORS.green },
      { name: "Elevated", value: 25, color: COLORS.amber },
      { name: "High", value: 15, color: COLORS.red },
    ],
  };
}

function fitnessData(context: ChartContext) {
  if (isAny(context, /one-rep|max/)) {
    const oneRm = Math.abs(context.primaryValue) || moneySeed(context);
    return [100, 95, 90, 85, 80, 75, 70, 65].map((pct) => ({ label: `${pct}%`, value: Math.round(oneRm * pct / 100) }));
  }
  if (isAny(context, /heart/)) {
    const maxHr = Math.abs(context.primaryValue) || 190;
    return [
      { label: "Zone 1", value: Math.round(maxHr * 0.55) },
      { label: "Zone 2", value: Math.round(maxHr * 0.65) },
      { label: "Zone 3", value: Math.round(maxHr * 0.75) },
      { label: "Zone 4", value: Math.round(maxHr * 0.85) },
      { label: "Zone 5", value: Math.round(maxHr * 0.95) },
    ];
  }
  return (context.results.length ? context.results : context.inputs).slice(0, 7).map((point) => ({ label: point.label, value: Math.abs(point.value) }));
}

function bellData(context: ChartContext) {
  const marker = Number.isFinite(context.primaryValue) ? Math.max(-3, Math.min(3, context.primaryValue)) : 0;
  const data = Array.from({ length: 61 }, (_, index) => {
    const x = -3 + index * 0.1;
    const y = Math.exp(-0.5 * x * x);
    return { x: Number(x.toFixed(1)), y: Number(y.toFixed(4)), shaded: x <= marker ? Number(y.toFixed(4)) : 0 };
  });
  return { data, marker };
}

function percentData(context: ChartContext) {
  const before = findValue(context.inputs, /before|original|initial|old|price|amount/i, context.inputs[0]?.value || 100);
  const after = context.primaryValue || findValue(context.inputs, /after|new|sale|final/i, before * 1.1);
  return [
    { label: "Before", value: before },
    { label: "After", value: after },
  ];
}

function scienceLineData(context: ChartContext) {
  const base = Math.max(1, Math.abs(context.inputs[0]?.value || 10));
  const multiplier = Math.max(1, Math.abs(context.inputs[1]?.value || 4));
  const quadratic = isAny(context, /kinetic|square|velocity/);
  return Array.from({ length: 9 }, (_, index) => {
    const x = Math.round(base * (index + 1) / 2);
    const value = quadratic ? 0.5 * multiplier * x * x : multiplier * x;
    return { label: String(x), value: Math.round(value) };
  });
}

function investmentScenarioData(context: ChartContext) {
  const amount = moneySeed(context);
  const years = Math.round(yearsSeed(context, 10));
  return [3, 7, 10].map((rate) => ({
    rate: `${rate}%`,
    year1: Math.round(amount * Math.pow(1 + rate / 100, 1)),
    mid: Math.round(amount * Math.pow(1 + rate / 100, Math.max(2, years / 2))),
    final: Math.round(amount * Math.pow(1 + rate / 100, years)),
  }));
}

function incomeStackData(context: ChartContext) {
  const gross = moneySeed(context);
  const fica = Math.round(gross * 0.0765);
  const federal = Math.round(gross * 0.12);
  const state = Math.round(gross * 0.04);
  const net = Math.max(0, gross - fica - federal - state);
  return [{ label: "Income", "Federal Tax": federal, "State Tax": state, FICA: fica, "Take Home": net }];
}

function conversionData(context: ChartContext) {
  const value = Math.abs(context.inputs[0]?.value || context.primaryValue || 1);
  return [
    { label: "Input", value },
    { label: "Metric", value: value * 1.609 },
    { label: "Imperial", value: value * 0.621 },
    { label: "Alt Unit", value: value * 1000 },
  ];
}

function timelineData(context: ChartContext, pregnancy = false) {
  if (pregnancy) {
    const current = Math.max(1, Math.min(40, Math.abs(context.primaryValue) || findValue(context.inputs, /week/i, 20)));
    return [
      { label: "Start", week: 0, value: 1 },
      { label: "12w", week: 12, value: 1 },
      { label: "20w", week: 20, value: 1 },
      { label: "28w", week: 28, value: 1 },
      { label: "Current", week: current, value: 1.18 },
      { label: "40w", week: 40, value: 1 },
    ].sort((a, b) => a.week - b.week);
  }
  const duration = Math.max(1, Math.abs(context.primaryValue) || 30);
  return [
    { label: "Start", day: 0, value: 1 },
    { label: "25%", day: Math.round(duration * 0.25), value: 1 },
    { label: "50%", day: Math.round(duration * 0.5), value: 1 },
    { label: "75%", day: Math.round(duration * 0.75), value: 1 },
    { label: "End", day: Math.round(duration), value: 1 },
  ];
}

function transportData(context: ChartContext) {
  const distance = Math.max(10, findValue(context.inputs, /distance|mile|km/i, Math.abs(context.primaryValue) || 300));
  const cost = Math.max(1, Math.abs(context.primaryValue) || findValue(context.inputs, /cost|price/i, 80));
  return Array.from({ length: 8 }, (_, index) => {
    const d = Math.round((distance / 7) * index);
    return { label: `${d}`, cost: Math.round((cost / distance) * d) };
  });
}

function projectionData(context: ChartContext) {
  const start = Math.max(1, Math.abs(context.primaryValue) || moneySeed(context));
  const growth = isAny(context, /youtube|subscriber|social|instagram|tiktok/) ? 0.08 : 0.05;
  return Array.from({ length: 12 }, (_, index) => ({
    month: `M${index + 1}`,
    value: Math.round(start * Math.pow(1 + growth, index)),
  }));
}

function freelanceData(context: ChartContext) {
  const gross = moneySeed(context);
  const fee = Math.round(gross * 0.2);
  const tax = Math.round((gross - fee) * 0.18);
  const net = Math.max(0, gross - fee - tax);
  return [
    { label: "Gross", value: gross, fill: COLORS.purple },
    { label: "Platform Fee", value: fee, fill: COLORS.orange },
    { label: "Estimated Tax", value: tax, fill: COLORS.red },
    { label: "Net", value: net, fill: COLORS.green },
  ];
}

function genericBarData(context: ChartContext) {
  const source = context.results.length ? context.results : context.inputs;
  return source.slice(0, 8).map((point) => ({ label: point.label, value: Math.abs(point.value) }));
}

function displayKind(kind: string) {
  if (kind.includes("donut")) return "Donut";
  if (kind.includes("timeline")) return "Timeline";
  if (kind.includes("scale")) return "Scale";
  if (kind.includes("dual")) return "Dual";
  if (kind.includes("bell")) return "Curve";
  if (kind.includes("geometry")) return "Diagram";
  if (kind.includes("stack")) return "Stacked";
  if (kind.includes("waterfall")) return "Breakdown";
  if (kind.includes("bar")) return "Bars";
  return "Trend";
}

function dataPointCount(context: ChartContext, kind: string) {
  if (kind === "loan-dual") {
    const schedule = loanScheduleData(context);
    return schedule.balanceData.length + schedule.splitData.length;
  }
  if (kind === "financial-growth") return financialGrowthData(context).length;
  if (kind === "budget-donut" || kind === "macro-donut" || kind === "energy-donut") return donutData(context, kind).length;
  if (kind === "health-scale") return 5;
  if (kind === "pregnancy-timeline" || kind === "date-timeline") return timelineData(context).length;
  if (kind === "bell") return bellData(context).data.length;
  if (kind === "geometry") return 3;
  if (kind === "science-line" || kind === "chem-line") return scienceLineData(context).length;
  if (kind === "transport-line") return transportData(context).length;
  if (kind === "youtube-line" || kind === "social-line") return projectionData(context).length;
  if (kind === "investment-bars") return investmentScenarioData(context).length;
  if (kind === "income-stack") return incomeStackData(context).length;
  if (kind === "freelance-waterfall") return freelanceData(context).length;
  if (kind === "conversion-bars") return conversionData(context).length;
  if (kind === "percent-bars") return percentData(context).length;
  return genericBarData(context).length;
}

function metricCards(context: ChartContext, kind: string) {
  const source = genericBarData(context);
  const max = source.reduce<ChartPoint | null>((best, point) => (!best || point.value > best.value ? point : best), null);
  const total = source.reduce((sum, point) => sum + Math.abs(point.value), 0);
  return [
    { label: "Top Value", value: max ? compact(max.value) : "0", detail: max?.label || "Result" },
    { label: "Visualization", value: displayKind(kind), detail: "Matched" },
    { label: "Data Points", value: String(Math.max(1, dataPointCount(context, kind))), detail: "Live" },
    { label: "Total", value: compact(total), detail: "Visible" },
  ];
}

function Placeholder() {
  return (
    <div className="relative z-10 grid h-full place-items-center text-center">
      <div className="max-w-sm rounded-2xl border border-dashed border-slate-300 bg-white/65 p-6 shadow-sm dark:border-white/15 dark:bg-white/[0.04]">
        <p className="text-sm font-black text-foreground">Calculate above to see your visual breakdown</p>
        <p className="mt-2 text-xs leading-relaxed text-muted-foreground">
          The chart will appear here after the calculator has enough input and result data.
        </p>
      </div>
    </div>
  );
}

function DonutChart({ data }: { data: Array<{ name: string; value: number }> }) {
  return (
    <div className="relative z-10 grid h-full gap-4 md:grid-cols-[1fr_0.9fr]">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Tooltip content={<ChartTooltip />} formatter={tooltipFormatter} />
          <Pie data={data} dataKey="value" nameKey="name" innerRadius="58%" outerRadius="86%" paddingAngle={3} animationDuration={700}>
            {data.map((_, index) => <Cell key={index} fill={PIE_COLORS[index % PIE_COLORS.length]} />)}
          </Pie>
        </PieChart>
      </ResponsiveContainer>
      <div className="grid content-center gap-2">
        {data.slice(0, 8).map((item, index) => (
          <div key={item.name} className="flex items-center justify-between rounded-xl border border-border/70 bg-background/70 px-3 py-2 text-xs font-bold">
            <span className="flex min-w-0 items-center gap-2">
              <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: PIE_COLORS[index % PIE_COLORS.length] }} />
              <span className="truncate">{item.name}</span>
            </span>
            <span>{compact(item.value)}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function GeometryDiagram({ context }: { context: ChartContext }) {
  const width = findValue(context.inputs, /width|base|length|side|radius/i, 10);
  const height = findValue(context.inputs, /height|depth|diameter/i, 6);
  const isCircle = isAny(context, /circle|sphere|cylinder/);
  const isTriangle = isAny(context, /triangle/);
  return (
    <div className="relative z-10 grid h-full place-items-center">
      <svg viewBox="0 0 420 260" className="h-full max-h-[19rem] w-full">
        <defs>
          <linearGradient id="shapeFill" x1="0" x2="1">
            <stop offset="0%" stopColor={COLORS.purple} stopOpacity="0.9" />
            <stop offset="100%" stopColor={COLORS.blue} stopOpacity="0.9" />
          </linearGradient>
        </defs>
        {isCircle ? (
          <>
            <circle cx="210" cy="130" r="82" fill="url(#shapeFill)" opacity="0.88" />
            <line x1="210" y1="130" x2="292" y2="130" stroke="#fff" strokeWidth="4" strokeLinecap="round" />
            <text x="230" y="118" fill="#fff" fontSize="16" fontWeight="800">r {compact(width)}</text>
          </>
        ) : isTriangle ? (
          <>
            <polygon points="210,44 72,218 348,218" fill="url(#shapeFill)" opacity="0.88" />
            <text x="190" y="34" fill="currentColor" className="fill-slate-700 dark:fill-slate-200" fontSize="15" fontWeight="800">height {compact(height)}</text>
            <text x="172" y="244" fill="currentColor" className="fill-slate-700 dark:fill-slate-200" fontSize="15" fontWeight="800">base {compact(width)}</text>
          </>
        ) : (
          <>
            <rect x="75" y="55" width="270" height="150" rx="20" fill="url(#shapeFill)" opacity="0.88" />
            <text x="184" y="44" fill="currentColor" className="fill-slate-700 dark:fill-slate-200" fontSize="15" fontWeight="800">width {compact(width)}</text>
            <text x="356" y="134" fill="currentColor" className="fill-slate-700 dark:fill-slate-200" fontSize="15" fontWeight="800">height {compact(height)}</text>
          </>
        )}
        <text x="210" y="132" textAnchor="middle" fill="#fff" fontSize="28" fontWeight="900">{compact(Math.abs(context.primaryValue) || width * height)}</text>
      </svg>
    </div>
  );
}

function renderChart(kind: string, context: ChartContext) {
  const grid = "hsl(var(--border))";
  const axis = "hsl(var(--muted-foreground))";

  if (kind === "budget-donut" || kind === "macro-donut" || kind === "energy-donut") {
    const data = donutData(context, kind).filter((item) => item.value > 0);
    if (data.length < 2) return <Placeholder />;
    return <DonutChart data={data} />;
  }

  if (kind === "loan-dual") {
    const { balanceData, splitData } = loanScheduleData(context);
    return (
      <div className="relative z-10 grid h-full grid-rows-2 gap-4">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={balanceData} margin={{ top: 8, right: 14, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="label" tick={{ fill: axis, fontSize: 11 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={48} />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            <Line type="monotone" name="Remaining Balance" dataKey="balance" stroke={COLORS.purple} strokeWidth={3} dot={false} animationDuration={650} />
          </LineChart>
        </ResponsiveContainer>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={splitData} margin={{ top: 4, right: 14, left: 0, bottom: 0 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="year" tick={{ fill: axis, fontSize: 11 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={48} />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            <Bar name="Principal" dataKey="principal" stackId="payment" fill={COLORS.purple} radius={[6, 6, 0, 0]} animationDuration={700} />
            <Bar name="Interest" dataKey="interest" stackId="payment" fill={COLORS.amber} radius={[6, 6, 0, 0]} animationDuration={700} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "financial-growth") {
    const data = financialGrowthData(context);
    const cross = data.find((item) => item.returns > item.principal)?.year;
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data} margin={{ top: 12, right: 18, left: 0, bottom: 4 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="year" tick={{ fill: axis, fontSize: 11 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={50} />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            {cross && <ReferenceLine x={cross} stroke={COLORS.amber} label={{ value: "returns exceed contributions", fill: COLORS.amber, fontSize: 11 }} />}
            <Area type="monotone" name="Principal Contributed" dataKey="principal" stackId="growth" stroke={COLORS.purple} fill={COLORS.purple} fillOpacity={0.78} animationDuration={700} />
            <Area type="monotone" name="Interest / Returns" dataKey="returns" stackId="growth" stroke={COLORS.green} fill={COLORS.green} fillOpacity={0.72} animationDuration={700} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "health-scale") {
    const scale = healthScale(context);
    const row = scale.segments.reduce<Record<string, string | number>>((acc, segment) => ({ ...acc, [segment.name]: segment.value }), { name: "Scale" });
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={[row]} layout="vertical" margin={{ top: 70, right: 26, left: 20, bottom: 62 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.45} />
            <XAxis type="number" domain={scale.domain} tick={{ fill: axis, fontSize: 12 }} />
            <YAxis type="category" dataKey="name" hide />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            <ReferenceLine x={scale.value} stroke={COLORS.purple} strokeWidth={3} label={{ value: `${context.primaryLabel}: ${formatNumber(scale.value)}`, fill: COLORS.purple, fontSize: 12 }} />
            {scale.segments.map((segment) => (
              <Bar key={segment.name} dataKey={segment.name} stackId="scale" fill={segment.color} radius={[12, 12, 12, 12]} animationDuration={700} />
            ))}
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "fitness-bars" || kind === "conversion-bars" || kind === "result-bars") {
    const data = kind === "fitness-bars" ? fitnessData(context) : kind === "conversion-bars" ? conversionData(context) : genericBarData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} layout="vertical" margin={{ top: 8, right: 24, left: 12, bottom: 8 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis type="number" tick={{ fill: axis, fontSize: 11 }} />
            <YAxis type="category" dataKey="label" tick={{ fill: axis, fontSize: 11 }} width={92} />
            <Tooltip content={<ChartTooltip />} />
            <Bar name="Value" dataKey="value" fill={COLORS.purple} radius={[0, 10, 10, 0]} animationDuration={700}>
              {data.map((_, index) => <Cell key={index} fill={PIE_COLORS[index % PIE_COLORS.length]} />)}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "pregnancy-timeline" || kind === "date-timeline") {
    const pregnancy = kind === "pregnancy-timeline";
    const data = timelineData(context, pregnancy);
    const xKey = pregnancy ? "week" : "day";
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data} margin={{ top: 80, right: 28, left: 28, bottom: 70 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.45} />
            <XAxis dataKey={xKey} type="number" domain={["dataMin", "dataMax"]} tick={{ fill: axis, fontSize: 11 }} label={{ value: pregnancy ? "Weeks" : "Days", position: "insideBottom", offset: -12, fill: axis }} />
            <YAxis hide domain={[0.7, 1.35]} />
            <Tooltip content={<ChartTooltip />} />
            <Line type="monotone" dataKey="value" name="Milestone" stroke={COLORS.purple} strokeWidth={4} dot={{ r: 7, fill: COLORS.amber }} animationDuration={700} />
            {data.map((point) => <ReferenceLine key={point.label} x={point[xKey as keyof typeof point] as number} stroke={COLORS.blue} strokeOpacity={0.28} label={{ value: point.label, fill: axis, fontSize: 11 }} />)}
          </LineChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "bell") {
    const { data, marker } = bellData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data} margin={{ top: 12, right: 22, left: 8, bottom: 12 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="x" type="number" domain={[-3, 3]} tick={{ fill: axis, fontSize: 11 }} />
            <YAxis hide />
            <Tooltip content={<ChartTooltip />} />
            <ReferenceLine x={marker} stroke={COLORS.amber} strokeWidth={3} label={{ value: `value ${formatNumber(marker)}`, fill: COLORS.amber, fontSize: 12 }} />
            <Area type="monotone" dataKey="shaded" name="Shaded Area" stroke="none" fill={COLORS.purple} fillOpacity={0.24} animationDuration={700} />
            <Area type="monotone" dataKey="y" name="Distribution" stroke={COLORS.purple} fill="transparent" strokeWidth={3} animationDuration={700} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "percent-bars") {
    const data = percentData(context);
    const color = data[1].value >= data[0].value ? COLORS.green : COLORS.red;
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} margin={{ top: 28, right: 26, left: 4, bottom: 10 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="label" tick={{ fill: axis, fontSize: 12 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={50} />
            <Tooltip content={<ChartTooltip />} />
            <Bar dataKey="value" name="Value" radius={[12, 12, 0, 0]} animationDuration={700}>
              <Cell fill={COLORS.purple} />
              <Cell fill={color} />
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "geometry") return <GeometryDiagram context={context} />;

  if (kind === "science-line" || kind === "chem-line") {
    if (kind === "chem-line" && isAny(context, /ph-/)) {
      const value = Math.max(0, Math.min(14, Math.abs(context.primaryValue) || 7));
      const data = [{ label: "pH Scale", Acidic: 7, Neutral: 1, Basic: 6 }];
      return (
        <div className="relative z-10 h-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data} layout="vertical" margin={{ top: 80, right: 28, left: 20, bottom: 70 }}>
              <XAxis type="number" domain={[0, 14]} tick={{ fill: axis, fontSize: 12 }} />
              <YAxis type="category" dataKey="label" hide />
              <Tooltip content={<ChartTooltip />} />
              <Legend />
              <ReferenceLine x={value} stroke={COLORS.purple} strokeWidth={3} label={{ value: `pH ${formatNumber(value)}`, fill: COLORS.purple, fontSize: 12 }} />
              <Bar dataKey="Acidic" stackId="ph" fill={COLORS.red} radius={[10, 0, 0, 10]} />
              <Bar dataKey="Neutral" stackId="ph" fill={COLORS.green} />
              <Bar dataKey="Basic" stackId="ph" fill={COLORS.blue} radius={[0, 10, 10, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      );
    }
    const data = scienceLineData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data} margin={{ top: 12, right: 22, left: 4, bottom: 14 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="label" tick={{ fill: axis, fontSize: 11 }} label={{ value: "Input variable", position: "insideBottom", offset: -8, fill: axis }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={54} label={{ value: "Output", angle: -90, position: "insideLeft", fill: axis }} />
            <Tooltip content={<ChartTooltip />} />
            <Line type={kind === "chem-line" ? "monotone" : "basis"} dataKey="value" name="Calculated Output" stroke={COLORS.purple} strokeWidth={4} dot={{ r: 4, fill: COLORS.amber }} animationDuration={700} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "investment-bars") {
    const data = investmentScenarioData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} margin={{ top: 16, right: 24, left: 0, bottom: 8 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="rate" tick={{ fill: axis, fontSize: 12 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={56} />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            <Bar dataKey="year1" name="Year 1" fill={COLORS.blue} radius={[8, 8, 0, 0]} />
            <Bar dataKey="mid" name="Midpoint" fill={COLORS.purple} radius={[8, 8, 0, 0]} />
            <Bar dataKey="final" name="Final" fill={COLORS.green} radius={[8, 8, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "income-stack") {
    const data = incomeStackData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} layout="vertical" margin={{ top: 80, right: 26, left: 20, bottom: 70 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.45} />
            <XAxis type="number" tick={{ fill: axis, fontSize: 11 }} />
            <YAxis type="category" dataKey="label" hide />
            <Tooltip content={<ChartTooltip />} />
            <Legend />
            <Bar dataKey="Federal Tax" stackId="income" fill={COLORS.red} radius={[10, 0, 0, 10]} />
            <Bar dataKey="State Tax" stackId="income" fill={COLORS.orange} />
            <Bar dataKey="FICA" stackId="income" fill={COLORS.amber} />
            <Bar dataKey="Take Home" stackId="income" fill={COLORS.green} radius={[0, 10, 10, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "transport-line" || kind === "youtube-line" || kind === "social-line") {
    const data = kind === "transport-line" ? transportData(context) : projectionData(context);
    const xKey = kind === "transport-line" ? "label" : "month";
    const yKey = kind === "transport-line" ? "cost" : "value";
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data} margin={{ top: 12, right: 22, left: 4, bottom: 14 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey={xKey} tick={{ fill: axis, fontSize: 11 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={54} />
            <Tooltip content={<ChartTooltip />} />
            <Line type="monotone" dataKey={yKey} name={kind === "transport-line" ? "Fuel Cost" : "Projection"} stroke={COLORS.purple} strokeWidth={4} dot={{ r: 4, fill: COLORS.amber }} animationDuration={700} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    );
  }

  if (kind === "freelance-waterfall") {
    const data = freelanceData(context);
    return (
      <div className="relative z-10 h-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} margin={{ top: 22, right: 22, left: 4, bottom: 10 }}>
            <CartesianGrid stroke={grid} strokeDasharray="3 3" opacity={0.55} />
            <XAxis dataKey="label" tick={{ fill: axis, fontSize: 12 }} />
            <YAxis tick={{ fill: axis, fontSize: 11 }} width={56} />
            <Tooltip content={<ChartTooltip />} />
            <Bar dataKey="value" name="Amount" radius={[12, 12, 0, 0]} animationDuration={700}>
              {data.map((item) => <Cell key={item.label} fill={item.fill} />)}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    );
  }

  return <Placeholder />;
}

